'use client'
import { useSession, signOut } from 'next-auth/react'
import { useEffect, useRef, useState } from 'react'
import { useRouter } from 'next/navigation'


const FONT = 'Georgia, serif'
const MONO = "'Courier New', monospace"
const PRIORITY_COLOR: any = { CRITICAL:'#DC2626', HIGH:'#D97706', MEDIUM:'#2563EB', LOW:'#64748B' }
const PRIORITY_BG: any    = { CRITICAL:'#FEF2F2', HIGH:'#FFFBEB', MEDIUM:'#EFF6FF', LOW:'#F8FAFC' }
const STATUS_COLOR: any   = { OPEN:'#2563EB', IN_PROGRESS:'#D97706', RESOLVED:'#059669', CLOSED:'#94A3B8', ON_HOLD:'#7C3AED' }
const STATUS_BG: any      = { OPEN:'#EFF6FF', IN_PROGRESS:'#FFFBEB', RESOLVED:'#ECFDF5', CLOSED:'#F8FAFC', ON_HOLD:'#F5F3FF' }
const DEPT_LABEL: any     = { IT:'IT Support', STUDENT_SERVICES:'Student Services', FACILITIES:'Facilities', HR:'HR & Admin' }

function Badge({ color, bg, children }: any) {
  return <span style={{ fontSize:11, fontWeight:700, color, background:bg, padding:'3px 9px', borderRadius:5, fontFamily:MONO, whiteSpace:'nowrap' }}>{children}</span>
}

export default function PortalPage() {
  const { data: session, status } = useSession()
  const router = useRouter()

  const [branding, setBranding]     = useState<any>(null)
  const [logoError, setLogoError]   = useState(false)
  const [tab, setTab]               = useState('tickets')
  const [tickets, setTickets]       = useState<any[]>([])
  const [loading, setLoading]       = useState(true)
  const [selectedTicket, setSelectedTicket] = useState<any>(null)
  const [ticketDetail, setTicketDetail]     = useState<any>(null)
  const [replyMsg, setReplyMsg]     = useState('')
  const [submitting, setSubmitting] = useState(false)
  const [showNew, setShowNew]       = useState(false)
  const [newTicket, setNewTicket]   = useState({ title:'', description:'', department:'IT', priority:'MEDIUM', categoryId:'' })
  const [toast, setToast]           = useState('')
  const [depts, setDepts]           = useState<any[]>([])
  const [categories, setCategories] = useState<any[]>([])
  const [attachFiles, setAttachFiles] = useState<File[]>([])
  const [replyFiles, setReplyFiles]   = useState<File[]>([])
  const [storageConfig, setStorageConfig] = useState<{ maxFileSizeMb: number; allowedExtensions: string[] }>({ maxFileSizeMb: 10, allowedExtensions: [] })
  const [kbArticles, setKbArticles]   = useState<any[]>([])
  const [kbSearch, setKbSearch]       = useState('')
  const [kbSelected, setKbSelected]   = useState<any>(null)
  const [closing, setClosing]         = useState(false)
  const detailsRef = useRef<HTMLDivElement>(null)
  const replyRef   = useRef<HTMLDivElement>(null)

  const role = (session?.user as any)?.role ?? ''

  const accent      = branding?.primaryColor ?? (role === 'TEACHER' || role === 'STAFF' ? '#7C3AED' : '#2563EB')
  const portalTitle = branding?.portalTitle  ?? 'EduDesk'
  const welcome     = branding?.welcomeMessage ?? null

  const showToast = (msg: string) => { setToast(msg); setTimeout(() => setToast(''), 3000) }

  useEffect(() => {
    if (status === 'unauthenticated') router.push('/login')
    if (status === 'authenticated') {
      if (['SUPER_ADMIN','TENANT_ADMIN'].includes(role)) router.push('/')
      if (role === 'IT_AGENT') router.push('/dashboard')
    }
  }, [status, role])

  useEffect(() => {
    if (status !== 'authenticated') return
    fetchBranding()
    fetchTickets()
    fetchDepts()
    fetchCategories()
    fetchStorageConfig()
  }, [status])

  useEffect(() => {
    if (tab === 'kb') fetchKb()
  }, [tab])

  async function fetchBranding() {
    const r = await fetch('/api/portal/branding')
    const d = await r.json().catch(() => ({}))
    if (d.success && d.data) setBranding(d.data)
  }

  async function fetchDepts() {
    const r = await fetch('/api/tenant/departments').catch(() => null)
    if (!r) return
    const d = await r.json().catch(() => ({}))
    if (d.success) setDepts(d.data)
  }

  async function fetchCategories() {
    const r = await fetch('/api/tenant/categories?flat=true').catch(() => null)
    if (!r) return
    const d = await r.json().catch(() => ({}))
    if (d.success) setCategories((d.data ?? []).filter((c: any) => c.isActive))
  }

  async function fetchStorageConfig() {
    const r = await fetch('/api/portal/storage-config').catch(() => null)
    if (!r) return
    const d = await r.json().catch(() => ({}))
    if (d.success) setStorageConfig(d.data)
  }

  async function fetchKb(q?: string) {
    const url = q ? `/api/kb?q=${encodeURIComponent(q)}` : '/api/kb'
    const r = await fetch(url).catch(() => null)
    if (!r) return
    const d = await r.json().catch(() => ({}))
    if (d.success) setKbArticles(d.data)
  }

  async function closeTicket() {
    if (!ticketDetail) return
    if (!confirm('Close this ticket? You can no longer reply once closed.')) return
    setClosing(true)
    const res  = await fetch(`/api/tickets/${ticketDetail.id}`, { method:'PATCH', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ status:'CLOSED' }) })
    const data = await res.json().catch(() => ({}))
    if (data.success) {
      setTickets(prev => prev.map(t => t.id === ticketDetail.id ? { ...t, status:'CLOSED' } : t))
      setSelectedTicket((prev: any) => ({ ...prev, status:'CLOSED' }))
      setTicketDetail((prev: any) => ({ ...prev, status:'CLOSED' }))
      showToast('Ticket closed.')
    } else {
      showToast('Error: ' + (data.error ?? 'Could not close ticket'))
    }
    setClosing(false)
  }

  // ── WYSIWYG toolbar: apply formatting via execCommand ───────────────────────
  function applyFormat(format: string) {
    const editor = detailsRef.current
    if (!editor) return
    editor.focus()
    if (format === 'bold')          document.execCommand('bold',                false)
    else if (format === 'italic')   document.execCommand('italic',              false)
    else if (format === 'heading')  document.execCommand('formatBlock',         false, 'h3')
    else if (format === 'bullet')   document.execCommand('insertUnorderedList', false)
    else if (format === 'numbered') document.execCommand('insertOrderedList',   false)
    // Sync HTML state in case input event doesn't fire
    setNewTicket(p => ({ ...p, description: editor.innerHTML }))
  }

  function applyReplyFormat(format: string) {
    const editor = replyRef.current
    if (!editor) return
    editor.focus()
    if (format === 'bold')          document.execCommand('bold',                false)
    else if (format === 'italic')   document.execCommand('italic',              false)
    else if (format === 'underline') document.execCommand('underline',          false)
    else if (format === 'heading')  document.execCommand('formatBlock',         false, 'h3')
    else if (format === 'bullet')   document.execCommand('insertUnorderedList', false)
    else if (format === 'numbered') document.execCommand('insertOrderedList',   false)
    setReplyMsg(editor.textContent ?? '')
  }

  async function fetchTickets() {
    setLoading(true)
    const r = await fetch('/api/tickets?limit=50')
    const d = await r.json().catch(() => ({}))
    if (d.success) setTickets(d.data.tickets ?? [])
    setLoading(false)
  }

  async function openTicket(t: any) {
    setSelectedTicket(t)
    setTicketDetail(null)
    const r    = await fetch(`/api/tickets/${t.id}`)
    const data = await r.json().catch(() => ({}))
    if (data.success) setTicketDetail(data.data)
    else setTicketDetail({ ...t, messages: [] })
  }

  async function sendReply() {
    const htmlBody = replyRef.current?.innerHTML ?? ''
    const textBody = replyRef.current?.textContent?.trim() ?? ''
    if (!textBody || !ticketDetail) return
    setSubmitting(true)
    const r    = await fetch(`/api/tickets/${ticketDetail.id}/messages`, { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ messageBody: htmlBody, isInternal: false }) })
    const data = await r.json().catch(() => ({}))
    if (data.success) {
      setReplyMsg('')
      if (replyRef.current) replyRef.current.innerHTML = ''
      if (replyFiles.length > 0) {
        for (const file of replyFiles) {
          const fd = new FormData()
          fd.append('file', file)
          fd.append('messageId', data.data.id)
          await fetch(`/api/tickets/${ticketDetail.id}/attachments`, { method: 'POST', body: fd }).catch(() => {})
        }
        setReplyFiles([])
        // Refresh to show attachments on the message
        const refreshR = await fetch(`/api/tickets/${ticketDetail.id}`)
        const refreshD = await refreshR.json().catch(() => ({}))
        if (refreshD.success) setTicketDetail(refreshD.data)
      } else {
        setTicketDetail((p: any) => ({ ...p, messages: [...(p.messages??[]), data.data] }))
      }
    } else {
      showToast('Error: ' + (data.error ?? 'Could not send reply'))
    }
    setSubmitting(false)
  }

  function addReplyFiles(files: FileList | null) {
    if (!files) return
    Array.from(files).forEach(file => {
      const ext = file.name.split('.').pop()?.toLowerCase() ?? ''
      if (storageConfig.allowedExtensions.length > 0 && !storageConfig.allowedExtensions.includes(ext)) {
        showToast(`.${ext} is not an allowed file type`); return
      }
      if (file.size > storageConfig.maxFileSizeMb * 1024 * 1024) {
        showToast(`${file.name} exceeds the ${storageConfig.maxFileSizeMb} MB limit`); return
      }
      setReplyFiles(prev => [...prev, file])
    })
  }

  async function submitTicket() {
    const descText = detailsRef.current?.textContent?.trim() ?? ''
    if (!newTicket.title || !descText) return
    setSubmitting(true)
    const payload: any = { ...newTicket }
    if (!payload.categoryId) delete payload.categoryId
    const r    = await fetch('/api/tickets', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(payload) })
    const data = await r.json().catch(() => ({}))
    if (data.success) {
      // Upload any attachments
      if (attachFiles.length > 0) {
        for (const file of attachFiles) {
          const fd = new FormData()
          fd.append('file', file)
          await fetch(`/api/tickets/${data.data.id}/attachments`, { method:'POST', body: fd }).catch(() => {})
        }
      }
      setTickets(p => [data.data, ...p])
      setShowNew(false)
      setNewTicket({ title:'', description:'', department:'IT', priority:'MEDIUM', categoryId:'' })
      if (detailsRef.current) detailsRef.current.innerHTML = ''
      setAttachFiles([])
      showToast('Ticket submitted!')
    } else {
      showToast('Error: ' + (data.error ?? 'Failed'))
    }
    setSubmitting(false)
  }

  const openTickets   = tickets.filter(t => ['OPEN','IN_PROGRESS','ON_HOLD'].includes(t.status))
  const closedTickets = tickets.filter(t => ['RESOLVED','CLOSED'].includes(t.status))

  const deptOptions = depts.length > 0
    ? depts.filter(d => d.isActive).map(d => ({ value: d.department, label: `${d.icon || ''} ${d.label}`.trim() }))
    : [
        { value:'IT', label:'🖥️ IT Support' },
        { value:'STUDENT_SERVICES', label:'🎓 Student Services' },
        { value:'FACILITIES', label:'🏛️ Facilities' },
        { value:'HR', label:'👥 HR & Admin' },
      ]

  if (status === 'loading') return <div style={{ display:'flex', alignItems:'center', justifyContent:'center', height:'100vh', fontFamily:FONT }}>Loading…</div>

  return (
    <div style={{ minHeight:'100vh', background:'#F8FAFC', fontFamily:FONT }}>
      <style>{`
        [contenteditable] h3 { font-size:15px; font-weight:700; margin:6px 0 3px; }
        [contenteditable] ul { margin:4px 0 4px 18px; padding:0; list-style:disc; }
        [contenteditable] ol { margin:4px 0 4px 18px; padding:0; list-style:decimal; }
        [contenteditable] li { margin:2px 0; }
        [contenteditable] strong { font-weight:700; }
        [contenteditable] em { font-style:italic; }
      `}</style>

      {/* Topbar */}
      <div style={{ background:'white', borderBottom:'1px solid #E2E8F0', padding:'0 28px' }}>
        <div style={{ maxWidth:860, margin:'0 auto', display:'flex', alignItems:'center', justifyContent:'space-between', height:60 }}>
          <div style={{ display:'flex', alignItems:'center', gap:10 }}>
            {branding?.logoUrl && !logoError
              ? <img src={branding.logoUrl} alt='logo' style={{ height:32, objectFit:'contain' }} onError={() => setLogoError(true)} />
              : <div style={{ fontSize:20, fontWeight:900 }}>{portalTitle.split(' ')[0]}<span style={{ color:accent }}>{portalTitle.split(' ').slice(1).join(' ') || 'Desk'}</span></div>
            }
            <div style={{ fontSize:10, color:'#94A3B8', fontFamily:MONO, letterSpacing:1 }}>{role} PORTAL</div>
          </div>
          <div style={{ display:'flex', alignItems:'center', gap:12 }}>
            <div style={{ textAlign:'right' }}>
              <div style={{ fontSize:13, fontWeight:700 }}>{session?.user?.name}</div>
              <div style={{ fontSize:10, color:'#94A3B8', fontFamily:MONO }}>{(session?.user as any)?.tenantName ?? ''}</div>
            </div>
            <div style={{ width:36, height:36, borderRadius:'50%', background:`${accent}22`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:14, fontWeight:800, color:accent }}>
              {session?.user?.name?.[0] ?? '?'}
            </div>
            <button onClick={() => signOut({ callbackUrl:'/login' })} style={{ fontSize:12, color:'#94A3B8', background:'none', border:'none', cursor:'pointer' }}>Sign out</button>
          </div>
        </div>
      </div>

      <div style={{ maxWidth:860, margin:'0 auto', padding:'28px 24px' }}>

        {/* Hero banner */}
        <div style={{ background:`linear-gradient(120deg, ${accent}dd, ${accent})`, borderRadius:16, padding:'24px 28px', marginBottom:24, color:'white', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <div>
            <div style={{ fontSize:20, fontWeight:800, marginBottom:4 }}>Welcome back, {session?.user?.name?.split(' ')[0]} 👋</div>
            <div style={{ fontSize:13, opacity:0.85 }}>
              {welcome ?? (openTickets.length > 0 ? `You have ${openTickets.length} active ticket${openTickets.length !== 1 ? 's' : ''}.` : "You're all clear — no open tickets.")}
            </div>
          </div>
          <button onClick={() => setShowNew(true)} style={{ padding:'11px 22px', background:'white', color:accent, border:'none', borderRadius:10, fontSize:13, fontWeight:800, cursor:'pointer', whiteSpace:'nowrap' }}>+ New Ticket</button>
        </div>

        {/* Quick actions */}
        {(role === 'TEACHER' || role === 'STAFF') && (
          <div style={{ display:'grid', gridTemplateColumns:`repeat(${Math.min(deptOptions.length,4)},1fr)`, gap:12, marginBottom:24 }}>
            {deptOptions.slice(0,4).map(d => (
              <button key={d.value} onClick={() => { setNewTicket(p => ({ ...p, department: d.value })); setShowNew(true) }}
                style={{ background:'white', border:'1px solid #E2E8F0', borderRadius:12, padding:'16px 12px', cursor:'pointer', textAlign:'center', fontFamily:FONT }}
                onMouseEnter={e => (e.currentTarget.style.boxShadow = '0 4px 12px rgba(0,0,0,0.08)')}
                onMouseLeave={e => (e.currentTarget.style.boxShadow = 'none')}>
                <div style={{ fontSize:22, marginBottom:6 }}>{'🖥📚🏛👥'.split('')[deptOptions.indexOf(d)] ?? '🔧'}</div>
                <div style={{ fontSize:12, fontWeight:700, color:accent }}>{d.label}</div>
              </button>
            ))}
          </div>
        )}

        {/* Tabs */}
        <div style={{ display:'flex', borderBottom:'2px solid #E2E8F0', marginBottom:24 }}>
          {[{ id:'tickets', label:'My Tickets' }, { id:'kb', label:'Self-Help' }].map(t => (
            <button key={t.id} onClick={() => setTab(t.id)} style={{ padding:'11px 20px', border:'none', background:'none', cursor:'pointer', fontSize:13, fontWeight: tab===t.id ? 700 : 400, color: tab===t.id ? accent : '#64748B', borderBottom:`2px solid ${tab===t.id ? accent : 'transparent'}`, marginBottom:-2, fontFamily:FONT }}>
              {t.label}
            </button>
          ))}
        </div>

        {tab === 'tickets' && (
          <div>
            {loading && <div style={{ textAlign:'center', color:'#94A3B8', padding:40 }}>Loading…</div>}
            {!loading && tickets.length === 0 && (
              <div style={{ textAlign:'center', padding:60, color:'#94A3B8' }}>
                <div style={{ fontSize:40, marginBottom:12 }}>🎉</div>
                <div style={{ fontSize:15, fontWeight:700 }}>No tickets yet</div>
                <div style={{ fontSize:13, marginTop:4 }}>Submit a ticket if you need help.</div>
              </div>
            )}
            {openTickets.length > 0 && (
              <>
                <div style={{ fontSize:11, color:'#94A3B8', fontFamily:MONO, marginBottom:12 }}>ACTIVE — {openTickets.length}</div>
                <div style={{ display:'flex', flexDirection:'column', gap:12, marginBottom:28 }}>
                  {openTickets.map(t => <TicketCard key={t.id} ticket={t} accent={accent} onClick={() => openTicket(t)} />)}
                </div>
              </>
            )}
            {closedTickets.length > 0 && (
              <>
                <div style={{ fontSize:11, color:'#94A3B8', fontFamily:MONO, marginBottom:12 }}>CLOSED — {closedTickets.length}</div>
                <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
                  {closedTickets.map(t => <TicketCard key={t.id} ticket={t} accent={accent} onClick={() => openTicket(t)} />)}
                </div>
              </>
            )}
          </div>
        )}

        {tab === 'kb' && (
          <div>
            {/* KB search bar */}
            <div style={{ marginBottom:18, display:'flex', gap:10 }}>
              <input value={kbSearch} onChange={e => { setKbSearch(e.target.value); fetchKb(e.target.value || undefined) }}
                placeholder='Search knowledge base…'
                style={{ flex:1, padding:'10px 14px', border:'1px solid #E2E8F0', borderRadius:10, fontSize:13, fontFamily:FONT, outline:'none' }} />
              {kbSearch && <button onClick={() => { setKbSearch(''); fetchKb() }} style={{ padding:'10px 14px', border:'1px solid #E2E8F0', borderRadius:10, background:'white', cursor:'pointer', fontSize:12, color:'#64748B' }}>Clear</button>}
            </div>

            {kbSelected ? (
              /* Article reader */
              <div style={{ background:'white', border:'1px solid #E2E8F0', borderRadius:14, overflow:'hidden' }}>
                <div style={{ padding:'18px 24px', borderBottom:'1px solid #F1F5F9', display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
                  <div>
                    <button onClick={() => setKbSelected(null)} style={{ fontSize:12, color:'#64748B', background:'none', border:'none', cursor:'pointer', padding:0, marginBottom:8 }}>← Back to articles</button>
                    <div style={{ fontSize:18, fontWeight:800, color:'#0F172A' }}>{kbSelected.title}</div>
                    {kbSelected.department && <div style={{ fontSize:11, color:'#94A3B8', fontFamily:MONO, marginTop:4 }}>{kbSelected.department}</div>}
                  </div>
                </div>
                <div style={{ padding:'20px 24px', fontSize:14, lineHeight:1.8, color:'#334155' }}
                  dangerouslySetInnerHTML={{ __html: kbSelected.body }} />
              </div>
            ) : kbArticles.length === 0 ? (
              <div style={{ textAlign:'center', padding:60, color:'#94A3B8' }}>
                <div style={{ fontSize:32, marginBottom:12 }}>📚</div>
                <div style={{ fontSize:14, fontWeight:700 }}>{kbSearch ? 'No articles match your search' : 'No knowledge base articles yet'}</div>
              </div>
            ) : (
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
                {kbArticles.map((a: any) => (
                  <div key={a.id} onClick={() => { setKbSelected(a); fetch(`/api/kb`, { method:'PATCH', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ id: a.id }) }) }}
                    style={{ background:'white', border:'1px solid #E2E8F0', borderRadius:12, padding:'16px 18px', cursor:'pointer', display:'flex', gap:12, alignItems:'flex-start' }}
                    onMouseEnter={e => (e.currentTarget.style.boxShadow = '0 4px 12px rgba(0,0,0,0.07)')}
                    onMouseLeave={e => (e.currentTarget.style.boxShadow = 'none')}>
                    <span style={{ fontSize:22, flexShrink:0 }}>📄</span>
                    <div style={{ minWidth:0 }}>
                      <div style={{ fontSize:13, fontWeight:700, color:'#1E293B', lineHeight:1.4 }}>{a.title}</div>
                      {a.department && <div style={{ fontSize:11, color:'#94A3B8', fontFamily:MONO, marginTop:4 }}>{a.department}</div>}
                      {a.tags && <div style={{ fontSize:11, color:'#CBD5E1', marginTop:2, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{a.tags}</div>}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>

      {/* Ticket Detail */}
      {selectedTicket && (
        <div style={{ position:'fixed', inset:0, background:'rgba(15,23,42,0.4)', zIndex:100, display:'flex', alignItems:'center', justifyContent:'center' }} onClick={() => { setSelectedTicket(null); setTicketDetail(null); setReplyFiles([]) }}>
          <div onClick={e => e.stopPropagation()} style={{ width:520, maxHeight:'85vh', background:'white', borderRadius:18, boxShadow:'0 24px 64px rgba(0,0,0,0.15)', display:'flex', flexDirection:'column' }}>
            <div style={{ padding:'20px 24px', borderBottom:'1px solid #F1F5F9', display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
              <div>
                <div style={{ fontSize:11, color:'#94A3B8', fontFamily:MONO, marginBottom:4 }}>#{selectedTicket.ticketNumber} · {DEPT_LABEL[selectedTicket.department] ?? selectedTicket.department}</div>
                <div style={{ fontSize:15, fontWeight:700, color:'#0F172A', lineHeight:1.3 }}>{selectedTicket.title}</div>
                <div style={{ display:'flex', gap:6, marginTop:8 }}>
                  <Badge color={STATUS_COLOR[selectedTicket.status]} bg={STATUS_BG[selectedTicket.status]}>{selectedTicket.status.replace('_',' ')}</Badge>
                  <Badge color={PRIORITY_COLOR[selectedTicket.priority]} bg={PRIORITY_BG[selectedTicket.priority]}>{selectedTicket.priority}</Badge>
                </div>
              </div>
              <button onClick={() => { setSelectedTicket(null); setTicketDetail(null); setReplyFiles([]) }} style={{ border:'none', background:'#F1F5F9', borderRadius:8, width:32, height:32, cursor:'pointer', fontSize:18, color:'#64748B' }}>×</button>
            </div>

            <div style={{ flex:1, overflowY:'auto', padding:'18px 24px', display:'flex', flexDirection:'column', gap:12 }}>
              {!ticketDetail && <div style={{ textAlign:'center', color:'#94A3B8', paddingTop:20 }}>Loading…</div>}
              {/* Description block */}
              {ticketDetail?.description && (
                <div style={{ background:'#F8FAFC', borderRadius:10, padding:'12px 16px', borderLeft:`3px solid ${accent}`, marginBottom:4 }}>
                  <div style={{ fontSize:10, color:'#94A3B8', fontFamily:MONO, marginBottom:6 }}>TICKET DETAILS</div>
                  <div style={{ fontSize:13, color:'#334155', lineHeight:1.6 }} dangerouslySetInnerHTML={{ __html: ticketDetail.description }} />
                  {/* Ticket-level attachments (submitted with the ticket, no messageId) */}
                  {ticketDetail?.attachments?.filter((a: any) => !a.messageId).length > 0 && (
                    <div style={{ marginTop:10, paddingTop:10, borderTop:'1px solid #E2E8F0', display:'flex', flexDirection:'column', gap:4 }}>
                      <div style={{ fontSize:10, color:'#94A3B8', fontFamily:MONO, marginBottom:4 }}>ATTACHMENTS</div>
                      {ticketDetail.attachments.filter((a: any) => !a.messageId).map((att: any) => (
                        <a key={att.id} href={att.downloadUrl} target='_blank' rel='noreferrer'
                          style={{ fontSize:12, color:'#2563EB', fontFamily:MONO, textDecoration:'none', display:'flex', alignItems:'center', gap:5 }}>
                          📎 {att.fileName} <span style={{ color:'#94A3B8' }}>({(att.sizeBytes/1024).toFixed(0)} KB)</span>
                        </a>
                      ))}
                    </div>
                  )}
                </div>
              )}
              {ticketDetail?.messages?.map((m: any) => (
                <div key={m.id} style={{ display:'flex', flexDirection:'column', alignItems: m.author?.id === session?.user?.id ? 'flex-end' : 'flex-start' }}>
                  {m.author?.id !== session?.user?.id && <div style={{ fontSize:11, color:'#94A3B8', fontFamily:MONO, marginBottom:3 }}>{m.author?.name} · {new Date(m.createdAt).toLocaleTimeString()}</div>}
                  <div style={{ maxWidth:'80%', padding:'11px 15px', borderRadius: m.author?.id === session?.user?.id ? '16px 16px 4px 16px' : '16px 16px 16px 4px', background: m.author?.id === session?.user?.id ? accent : '#F1F5F9', color: m.author?.id === session?.user?.id ? 'white' : '#334155', fontSize:13, lineHeight:1.55 }}>
                    <div dangerouslySetInnerHTML={{ __html: m.body }} />
                    {m.attachments?.length > 0 && (
                      <div style={{ marginTop:8, display:'flex', flexDirection:'column', gap:4, borderTop:`1px solid ${m.author?.id === session?.user?.id ? 'rgba(255,255,255,0.25)' : 'rgba(0,0,0,0.06)'}`, paddingTop:8 }}>
                        {m.attachments.map((att: any) => (
                          <a key={att.id} href={att.downloadUrl} target='_blank' rel='noreferrer'
                            style={{ fontSize:11, color: m.author?.id === session?.user?.id ? 'rgba(255,255,255,0.9)' : '#2563EB', fontFamily:MONO, textDecoration:'none', display:'flex', alignItems:'center', gap:4 }}>
                            📎 {att.fileName}
                          </a>
                        ))}
                      </div>
                    )}
                  </div>
                  {m.author?.id === session?.user?.id && <div style={{ fontSize:11, color:'#94A3B8', fontFamily:MONO, marginTop:3 }}>You · {new Date(m.createdAt).toLocaleTimeString()}</div>}
                </div>
              ))}
            </div>

            {!['RESOLVED','CLOSED'].includes(selectedTicket.status) ? (
              <div style={{ padding:'14px 24px', borderTop:'1px solid #F1F5F9' }}>
                {/* Close ticket button */}
                <div style={{ display:'flex', justifyContent:'flex-end', marginBottom:10 }}>
                  <button onClick={closeTicket} disabled={closing}
                    style={{ padding:'6px 14px', background:'#FEF2F2', color:'#DC2626', border:'1px solid #FECACA', borderRadius:7, fontSize:12, cursor:'pointer', fontFamily:FONT, opacity: closing ? 0.6 : 1 }}>
                    {closing ? 'Closing…' : '✕ Close Ticket'}
                  </button>
                </div>
                {/* WYSIWYG reply toolbar */}
                <div style={{ display:'flex', flexWrap:'wrap', gap:4, padding:'5px 8px', background:'#F8FAFC', borderRadius:'10px 10px 0 0', border:'1px solid #E2E8F0', borderBottom:'none' }}>
                  {[
                    { fmt:'bold',     label:'B',      title:'Bold',          style:{ fontWeight:900 } },
                    { fmt:'italic',   label:'I',      title:'Italic',        style:{ fontStyle:'italic' } },
                    { fmt:'underline',label:'U',      title:'Underline',     style:{ textDecoration:'underline' } },
                    { fmt:'heading',  label:'H₃',     title:'Heading',       style:{ fontWeight:700, fontSize:11 } },
                    { fmt:'bullet',   label:'• List', title:'Bullet list',   style:{} },
                    { fmt:'numbered', label:'1. List',title:'Numbered list', style:{} },
                  ].map(btn => (
                    <button key={btn.fmt} type='button' title={btn.title}
                      onMouseDown={e => { e.preventDefault(); applyReplyFormat(btn.fmt) }}
                      style={{ padding:'3px 9px', border:'1px solid #E2E8F0', borderRadius:5, background:'white', cursor:'pointer', fontSize:12, fontFamily:MONO, ...btn.style }}>
                      {btn.label}
                    </button>
                  ))}
                </div>
                {/* contentEditable reply area */}
                <div style={{ position:'relative' }}>
                  {(!replyMsg) && (
                    <div style={{ position:'absolute', top:'10px', left:'13px', color:'#CBD5E1', fontSize:13, fontFamily:FONT, pointerEvents:'none', userSelect:'none' }}>
                      Reply to your ticket…
                    </div>
                  )}
                  <div
                    ref={replyRef}
                    contentEditable
                    suppressContentEditableWarning
                    onInput={() => setReplyMsg(replyRef.current?.textContent ?? '')}
                    style={{ minHeight:90, padding:'10px 12px', border:'1px solid #E2E8F0', borderRadius:'0 0 10px 10px', fontSize:13, fontFamily:FONT, outline:'none', lineHeight:1.7, wordBreak:'break-word', overflowY:'auto', boxSizing:'border-box' as const }}
                  />
                </div>
                {/* Selected reply files */}
                {replyFiles.length > 0 && (
                  <div style={{ display:'flex', flexWrap:'wrap', gap:5, marginTop:8 }}>
                    {replyFiles.map((f, i) => (
                      <div key={i} style={{ display:'flex', alignItems:'center', gap:4, background:'#EFF6FF', border:'1px solid #BFDBFE', borderRadius:5, padding:'3px 8px' }}>
                        <span style={{ fontSize:11, color:'#2563EB', fontFamily:MONO, maxWidth:130, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>📎 {f.name}</span>
                        <button onClick={() => setReplyFiles(prev => prev.filter((_, j) => j !== i))}
                          style={{ background:'none', border:'none', cursor:'pointer', color:'#94A3B8', fontSize:14, padding:'0 2px', lineHeight:1 }}>×</button>
                      </div>
                    ))}
                  </div>
                )}
                <div style={{ display:'flex', gap:8, marginTop:8 }}>
                  <label title={`Attach file (max ${storageConfig.maxFileSizeMb} MB)`}
                    style={{ padding:'9px 12px', background:'#F1F5F9', border:'1px solid #E2E8F0', borderRadius:9, cursor:'pointer', fontSize:14, color:'#64748B', display:'flex', alignItems:'center' }}>
                    📎
                    <input type='file' multiple
                      accept={storageConfig.allowedExtensions.map((e: string) => `.${e}`).join(',')}
                      onChange={e => { addReplyFiles(e.target.files); e.target.value = '' }}
                      style={{ display:'none' }} />
                  </label>
                  <button onClick={sendReply} disabled={submitting || !replyMsg.trim()} style={{ flex:1, padding:'9px 18px', background:accent, color:'white', border:'none', borderRadius:9, fontSize:13, fontWeight:700, cursor:'pointer', opacity: !replyMsg.trim() ? 0.5 : 1 }}>Send</button>
                </div>
              </div>
            ) : (
              <div style={{ padding:'14px 24px', borderTop:'1px solid #F1F5F9', textAlign:'center', fontSize:12, color:'#94A3B8', fontFamily:MONO }}>This ticket is {selectedTicket.status.toLowerCase()}</div>
            )}
          </div>
        </div>
      )}

      {/* New Ticket */}
      {showNew && (
        <div style={{ position:'fixed', inset:0, background:'rgba(15,23,42,0.4)', zIndex:100, display:'flex', alignItems:'center', justifyContent:'center' }} onClick={() => { setShowNew(false); if (detailsRef.current) detailsRef.current.innerHTML = '' }}>
          <div onClick={e => e.stopPropagation()} style={{ width:480, background:'white', borderRadius:18, padding:32, boxShadow:'0 24px 64px rgba(0,0,0,0.15)' }}>
            <div style={{ fontSize:18, fontWeight:800, marginBottom:4 }}>Submit a New Ticket</div>
            <div style={{ fontSize:13, color:'#94A3B8', marginBottom:22 }}>Describe your issue and we'll route it to the right team.</div>

            <div style={{ marginBottom:14 }}>
              <div style={{ fontSize:11, fontFamily:MONO, color:'#94A3B8', marginBottom:5 }}>TICKET SUBJECT</div>
              <input value={newTicket.title} onChange={e => setNewTicket({ ...newTicket, title: e.target.value })} placeholder='Briefly summarize your request…' style={{ width:'100%', padding:'10px 12px', border:'1px solid #E2E8F0', borderRadius:8, fontSize:13, fontFamily:FONT, outline:'none', boxSizing:'border-box' }} />
            </div>
            <div style={{ marginBottom:14 }}>
              <div style={{ fontSize:11, fontFamily:MONO, color:'#94A3B8', marginBottom:5 }}>TICKET DETAILS</div>
              {/* WYSIWYG toolbar */}
              <div style={{ display:'flex', gap:4, padding:'4px 6px', background:'#F8FAFC', borderRadius:'8px 8px 0 0', border:'1px solid #E2E8F0', borderBottom:'none' }}>
                {[
                  { fmt:'bold',     label:'B',  title:'Bold',          style:{ fontWeight:900 } },
                  { fmt:'italic',   label:'I',  title:'Italic',        style:{ fontStyle:'italic' } },
                  { fmt:'heading',  label:'H₃', title:'Heading',       style:{ fontWeight:700, fontSize:11 } },
                  { fmt:'bullet',   label:'• List', title:'Bullet list',  style:{} },
                  { fmt:'numbered', label:'1. List', title:'Numbered list', style:{} },
                ].map(btn => (
                  <button key={btn.fmt} type='button' title={btn.title}
                    onMouseDown={e => { e.preventDefault(); applyFormat(btn.fmt) }}
                    style={{ padding:'3px 10px', border:'1px solid #E2E8F0', borderRadius:5, background:'white', cursor:'pointer', fontSize:12, fontFamily:MONO, ...btn.style }}>
                    {btn.label}
                  </button>
                ))}
              </div>
              {/* contentEditable editor — WYSIWYG live formatting */}
              <div style={{ position:'relative' }}>
                {(!newTicket.description || newTicket.description === '<br>') && (
                  <div style={{ position:'absolute', top:'10px', left:'13px', color:'#CBD5E1', fontSize:13, fontFamily:FONT, pointerEvents:'none', userSelect:'none' }}>
                    Describe your request in detail…
                  </div>
                )}
                <div
                  ref={detailsRef}
                  contentEditable
                  suppressContentEditableWarning
                  onInput={() => setNewTicket(p => ({ ...p, description: detailsRef.current?.innerHTML ?? '' }))}
                  style={{ minHeight:120, padding:'10px 12px', border:'1px solid #E2E8F0', borderRadius:'0 0 8px 8px', fontSize:13, fontFamily:FONT, outline:'none', lineHeight:1.7, wordBreak:'break-word', overflowY:'auto', boxSizing:'border-box' as const }}
                />
              </div>
            </div>

            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:14 }}>
              <div>
                <div style={{ fontSize:11, fontFamily:MONO, color:'#94A3B8', marginBottom:5 }}>DEPARTMENT</div>
                <select value={newTicket.department} onChange={e => setNewTicket({ ...newTicket, department: e.target.value, categoryId: '' })} style={{ width:'100%', padding:'10px 12px', border:'1px solid #E2E8F0', borderRadius:8, fontSize:13, fontFamily:FONT, outline:'none' }}>
                  {deptOptions.map(d => <option key={d.value} value={d.value}>{d.label}</option>)}
                </select>
              </div>
              <div>
                <div style={{ fontSize:11, fontFamily:MONO, color:'#94A3B8', marginBottom:5 }}>PRIORITY</div>
                <select value={newTicket.priority} onChange={e => setNewTicket({ ...newTicket, priority: e.target.value })} style={{ width:'100%', padding:'10px 12px', border:'1px solid #E2E8F0', borderRadius:8, fontSize:13, fontFamily:FONT, outline:'none' }}>
                  {['LOW','MEDIUM','HIGH','CRITICAL'].map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>
            </div>

            {(() => {
              const deptRoots = categories.filter((c: any) => !c.parentId && (!c.department || c.department === newTicket.department))
              return deptRoots.length > 0 ? (
                <div style={{ marginBottom:14 }}>
                  <div style={{ fontSize:11, fontFamily:MONO, color:'#94A3B8', marginBottom:5 }}>CATEGORY <span style={{ color:'#CBD5E1' }}>(optional)</span></div>
                  <select value={newTicket.categoryId} onChange={e => setNewTicket({ ...newTicket, categoryId: e.target.value })} style={{ width:'100%', padding:'10px 12px', border:'1px solid #E2E8F0', borderRadius:8, fontSize:13, fontFamily:FONT, outline:'none' }}>
                    <option value=''>— Select a category —</option>
                    {deptRoots.map((root: any) => {
                      const subs = categories.filter((c: any) => c.parentId === root.id)
                      const prefix = root.icon ? root.icon + ' ' : ''
                      // No sub-categories → root is directly selectable (flat option)
                      if (subs.length === 0) {
                        return <option key={root.id} value={root.id}>{prefix}{root.name}</option>
                      }
                      // Has sub-categories → group header only, children are selectable
                      return (
                        <optgroup key={root.id} label={`${prefix}${root.name}`}>
                          {subs.map((sub: any) => (
                            <option key={sub.id} value={sub.id}>↳ {sub.name}</option>
                          ))}
                        </optgroup>
                      )
                    })}
                  </select>
                </div>
              ) : null
            })()}

            <div style={{ marginBottom:22 }}>
              <div style={{ fontSize:11, fontFamily:MONO, color:'#94A3B8', marginBottom:5 }}>
                ATTACHMENTS <span style={{ color:'#CBD5E1' }}>(optional)</span>
                {storageConfig.allowedExtensions.length > 0 && (
                  <span style={{ marginLeft:8, color:'#94A3B8' }}>· {storageConfig.allowedExtensions.join(', ')} · max {storageConfig.maxFileSizeMb} MB each</span>
                )}
              </div>
              <label style={{ display:'flex', alignItems:'center', gap:10, padding:'10px 14px', border:'1px dashed #CBD5E1', borderRadius:8, cursor:'pointer', background:'#F8FAFC' }}>
                <span style={{ fontSize:18 }}>📎</span>
                <span style={{ fontSize:13, color:'#64748B' }}>{attachFiles.length > 0 ? `${attachFiles.length} file(s) selected` : 'Click to attach files…'}</span>
                <input type='file' multiple
                  accept={storageConfig.allowedExtensions.map(e => `.${e}`).join(',')}
                  style={{ display:'none' }}
                  onChange={e => setAttachFiles(Array.from(e.target.files ?? []))}
                />
              </label>
              {attachFiles.length > 0 && (
                <div style={{ marginTop:8, display:'flex', flexWrap:'wrap', gap:6 }}>
                  {attachFiles.map((f, i) => (
                    <span key={i} style={{ fontSize:11, background:'#EFF6FF', color:'#2563EB', padding:'3px 10px', borderRadius:5, display:'flex', alignItems:'center', gap:6 }}>
                      {f.name}
                      <button onClick={() => setAttachFiles(p => p.filter((_, j) => j !== i))} style={{ background:'none', border:'none', cursor:'pointer', color:'#94A3B8', fontSize:13, lineHeight:1, padding:0 }}>×</button>
                    </span>
                  ))}
                </div>
              )}
            </div>

            <div style={{ display:'flex', gap:10 }}>
              <button onClick={() => { setShowNew(false); if (detailsRef.current) detailsRef.current.innerHTML = '' }} style={{ flex:1, padding:11, border:'1px solid #E2E8F0', borderRadius:9, background:'white', fontSize:13, cursor:'pointer', color:'#64748B', fontFamily:FONT }}>Cancel</button>
              <button onClick={submitTicket} disabled={submitting} style={{ flex:2, padding:11, background:accent, color:'white', border:'none', borderRadius:9, fontSize:13, fontWeight:700, cursor:'pointer', fontFamily:FONT }}>
                {submitting ? 'Submitting…' : 'Submit Ticket'}
              </button>
            </div>
          </div>
        </div>
      )}

      {toast && <div style={{ position:'fixed', bottom:24, left:'50%', transform:'translateX(-50%)', background:'#0F172A', color:'white', padding:'12px 24px', borderRadius:12, fontSize:13, fontWeight:600, zIndex:200 }}>{toast}</div>}
    </div>
  )
}

function TicketCard({ ticket, accent, onClick }: any) {
  return (
    <div onClick={onClick} style={{ background:'white', border:'1px solid #E2E8F0', borderRadius:12, padding:'18px 20px', cursor:'pointer', borderLeft:`4px solid ${STATUS_COLOR[ticket.status]}` }}
      onMouseEnter={e => (e.currentTarget.style.boxShadow = '0 4px 16px rgba(0,0,0,0.08)')}
      onMouseLeave={e => (e.currentTarget.style.boxShadow = 'none')}>
      <div style={{ display:'flex', justifyContent:'space-between', gap:12 }}>
        <div style={{ flex:1 }}>
          <div style={{ fontSize:11, color:'#94A3B8', fontFamily:MONO, marginBottom:3 }}>#{ticket.ticketNumber}</div>
          <div style={{ fontSize:14, fontWeight:700, color:'#1E293B', lineHeight:1.3 }}>{ticket.title}</div>
          <div style={{ fontSize:12, color:'#94A3B8', marginTop:5 }}>
            {ticket.assignee ? `Agent: ${ticket.assignee.name}` : 'Awaiting assignment'} · {new Date(ticket.createdAt).toLocaleDateString()}
          </div>
        </div>
        <div style={{ display:'flex', flexDirection:'column', gap:5, alignItems:'flex-end', flexShrink:0 }}>
          <Badge color={STATUS_COLOR[ticket.status]} bg={STATUS_BG[ticket.status]}>{ticket.status.replace('_',' ')}</Badge>
          <Badge color={PRIORITY_COLOR[ticket.priority]} bg={PRIORITY_BG[ticket.priority]}>{ticket.priority}</Badge>
        </div>
      </div>
    </div>
  )
}
